import sys

n, m = map(int, sys.stdin.readline().split())

a = [0] * (n + 1)
b = [0] * (n + 1)

for i in range(m):
    x, y = map(int, sys.stdin.readline().split())
    a[x] += 1
    b[y] += 1

x = 0
y = 0

for i in range(1, n + 1):
    if a[i] == m:
        x = i
    if b[i] == m:
        y = i

if x != 0 and y != 0:
    print("YES")
else:
    print("NO")
